import{_ as e,o as s,c as n,al as t}from"./chunks/framework.CMYqsPpI.js";const u=JSON.parse('{"title":"Local build of ReactantExtra","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/local-build.md","filePath":"tutorials/local-build.md","lastUpdated":null}'),i={name:"tutorials/local-build.md"};function l(o,a,p,c,r,d){return s(),n("div",null,[...a[0]||(a[0]=[t('<h1 id="local-build" tabindex="-1">Local build of ReactantExtra <a class="header-anchor" href="#local-build" aria-label="Permalink to &quot;Local build of ReactantExtra {#local-build}&quot;">​</a></h1><p>In the <code>deps/</code> subdirectory of the Reactant repository there is a script to do local builds of ReactantExtra, including debug builds.</p><h2 id="Requirements" tabindex="-1">Requirements <a class="header-anchor" href="#Requirements" aria-label="Permalink to &quot;Requirements {#Requirements}&quot;">​</a></h2><ul><li><p>Julia. If you don&#39;t have it already, you can obtain it from the <a href="https://julialang.org/downloads/" target="_blank" rel="noreferrer">official Julia website</a></p></li><li><p>A reasonably recent C/C++ compiler, ideally GCC 12+. Older compilers may not work.</p></li><li><p>Bazel. If you don&#39;t have it already, you can download a build for your platform from <a href="https://github.com/bazelbuild/bazelisk/releases/latest" target="_blank" rel="noreferrer">the latest <code>bazelbuild/bazelisk</code> release</a> and put the <code>bazel</code> executable in <code>PATH</code>.</p></li><li><p>A fast linker like <code>lld</code> or <code>mold</code>. This is strictly speaking not necessary in general, but <code>lld</code> is used by default, and for debug builds with CUDA support, you&#39;ll need it. Binutils <code>ld</code> won&#39;t work, don&#39;t even try using it. You can obtain <code>mold</code> for your platform from the <a href="https://github.com/rui314/mold/releases/latest" target="_blank" rel="noreferrer">latest <code>rui314/mold</code> release</a> and put the executable in <code>PATH</code> with name <code>ld.mold</code>.</p></li></ul><p>On MacOS the latter two requirements can be installed with <code>brew install bazelisk lld</code>.</p><h2 id="Building" tabindex="-1">Building <a class="header-anchor" href="#Building" aria-label="Permalink to &quot;Building {#Building}&quot;">​</a></h2><p>At a high-level, after you <code>cd</code> to the <code>deps/</code> directory you can run the commands</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.instantiate()&#39;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # needed only the first time to install dependencies for this script</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --color=yes</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build_local.jl</span></span></code></pre></div><p>There are a few options you may want to use to tweak the build. For more information run the command</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build_local.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div><p>which prints the following (note that the output may be out of date; you should run it locally to see the options available to you):</p><p>usage: build_local.jl [–debug] [–backend BACKEND] [–gcc_host_compiler_path GCC_HOST_COMPILER_PATH] [–cc CC] [–hermetic_python_version HERMETIC_PYTHON_VERSION] [–jobs JOBS] [–copt COPT] [–cxxopt CXXOPT] [–extraopt EXTRAOPT] [–color COLOR] [–cache] [–push-cache] [-h]</p><p>optional arguments: –debug Build with debug mode (-c dbg). –backend BACKEND Build with the specified backend (auto, cpu, cuda). (default: &quot;auto&quot;) –gcc_host_compiler_path GCC_HOST_COMPILER_PATH Path to the gcc host compiler. (default: &quot;/usr/bin/gcc&quot;) –cc CC (default: &quot;/usr/bin/cc&quot;) –hermetic_python_version HERMETIC_PYTHON_VERSION Hermetic Python version. (default: &quot;3.12&quot;) –jobs JOBS Number of parallel jobs. (type: Int64, default: Sys.CPU_THREADS) –copt COPT Options to be passed to the C compiler. Can be used multiple times. –cxxopt CXXOPT Options to be passed to the C++ compiler. Can be used multiple times. –extraopt EXTRAOPT Extra options to be passed to Bazel. Can be used multiple times. –color COLOR Set to <code>yes</code> to enable color output, or <code>no</code> to disable it. Defaults to same color setting as the Julia process. –cache Build with bazel cache. –push-cache Build and store to bazel cache. -h, –help show this help message and exit</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>## Tips and tricks</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>### Doing a build on a system with memory or number of processes restrictions</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>If you try to do the build on certain systems which have restrictions on the number of processes or memory that your user can use (for example, login nodes of clusters), you may have to limit the number of parallel jobs used by Bazel.</span></span>\n<span class="line"><span>By default Bazel tries to use the maximum number of CPUs available on the system.</span></span>\n<span class="line"><span>If you need to reduce that, you can pass the `--jobs JOBS` flag option.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>If the Bazel server is terminated abruptly with an error which looks like</span></span></code></pre></div><p>Server terminated abruptly (error code: 14, error message: &#39;Socket closed&#39;, log file: &#39;/path/to/server/jvm.out&#39;)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>that may be due to the fact that the build process was using too many resources (e.g. if concurrent compiler processes are cumulatively using too much memory or too many threads).</span></span>\n<span class="line"><span>In this case, reducing the number of parallel jobs may also be beneficial.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>### CUDA debug build</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>A CUDA debug build (`--debug --backend=cuda`) requires a recent GCC compiler (at least v12) and also a fast linker (see requirements above).</span></span>\n<span class="line"><span>You can tell GCC to use either `lld` or `mold` with `--extraopt &#39;--linkopt=-fuse-ld=lld&#39;` or `--extraopt &#39;--linkopt=-fuse-ld=mold&#39;` respectively.</span></span>\n<span class="line"><span>NOTE: the option `-fuse-ld=mold` was added in GCC 12, if you&#39;re trying to use an older version you can have some luck by making a symlink named `ld` pointing to `mold` in `PATH`, with higher precedence than Binutils `ld`.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>### Optimised build with debug symbols</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Unoptimised builds of Reactant can be _extremely_ slow at runtime.</span></span>\n<span class="line"><span>You may have more luck by doing an optimised build that retains (i.e., doesn&#39;t strip) the debug symbols, which in Bazel can achieved with the options `--strip=never --copt -g -c opt`.</span></span>\n<span class="line"><span>To do that using this `build_local.jl` script pass the options `--extraopt &#39;--strip=never&#39; --copt -g` (optimised builds are the default, unless you use `--debug`).</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>### Using ccache</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>To speed up recompilation you can use [ccache](https://ccache.dev/).</span></span>\n<span class="line"><span>You can use ccache on top of Bazel&#39;s own caching system, which is very inflexible: Bazel invalidates cache whenever you change any variable, leading to poor cache hit rate when recompiling code with different options, even if they don&#39;t actually affect compilation output.</span></span>\n<span class="line"><span>Since [Bazel interacts badly with ccache](https://github.com/ccache/ccache/discussions/1279) when the latter [masquerades itself as the compiler via symlinks](https://ccache.dev/manual/4.11.3.html#_run_modes), the most reliable way to use ccache with Bazel is to create a small shell wrapper like</span></span></code></pre></div><p>bash #!/bin/bash /path/to/ccache /path/to/your/compiler &quot;${@}&quot;</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>replacing `/path/to/ccache` with the path where ccache was installed, and `/path/to/your/compiler` with the path of your compiler.</span></span>\n<span class="line"><span>Then inform Bazel to use this script as the compiler (with the `build_local.jl` script add the flag `--cc /path/to/ccache/wrapper`, where `/path/to/ccache/wrapper` is the path where you saved the shell wrapper).</span></span>\n<span class="line"><span>Finally, you may have to add the flag `--extraopt &quot;--sandbox_writable_path=/path/to/ccache/directory&quot;`, otherwise Bazel will not let `ccache` write the cache output to its own directory.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>## `LocalPreferences.toml` file</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>At the end of a successful build, the `build_local.jl` script will create a `LocalPreferences.toml` file (see [`Preferences.jl` documentation](https://juliapackaging.github.io/Preferences.jl/stable/) for more information) in the top-level of the Reactant repository, pointing `libReactantExtra` to the new local build. </span></span>\n<span class="line"><span>If you instantiate this environment, Reactant will automatically use the new local build.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>You can check that the local build is being used by running</span></span></code></pre></div><p>julia using Reactant_jll; Reactant_jll.libReactantExtra_path</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>which should point to the locally built library.</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>If you want to use the local build in a different environment:</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>1. copy the `LocalPreferences.toml` file (or its contents, if you already have a `LocalPreferences.toml` file) to the directory of that environment, and</span></span>\n<span class="line"><span>2. ensure that `Reactant_jll` is a direct dependency of that environment (i.e., add `Reactant_jll` to your `Project.toml` directly).</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>## Troubleshooting macOS builds</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>### Abseil module dependency</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>Depending on your compiler toolchain and Bazel version you may encounter an error like:</span></span></code></pre></div><p>console external/com_google_absl/absl/status/statusor.h:58:10: error: module com_google_absl//absl/status:statusor does not depend on a module exporting &#39;absl/types/span.h&#39;</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>This is caused by Bazel performing a strict version of dependency checking between C++ modules, which can be disabled with</span></span></code></pre></div><p>console julia [...] –extraopt &quot;–features=-layering_check&quot; –extraopt &quot;–host_features=-layering_check&quot;</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>### Toolchain for Intel macOS</span></span>\n<span class="line"><span></span></span>\n<span class="line"><span>One of Reactant&#39;s transitive dependencies, grpc, has a Bazel build configuration which [instructs it to build universal binaries on macOS](https://github.com/grpc/grpc/blob/8542e01ff47eb07247ff6cfbd545f3b6f4e9b5d3/bazel/grpc_build_system.bzl#L215-L225) (i.e., binaries which work on both Intel and Apple Silicon Macs).</span></span>\n<span class="line"><span>If your toolchain is not set up to do this, you may encounter a fairly cryptic error like:</span></span></code></pre></div><p>console ERROR: /path/to/...:72:19: in cc_toolchain_suite rule @@local_config_cc//:toolchain: cc_toolchain_suite &#39;@@local_config_cc//:toolchain&#39; does not contain a toolchain for cpu &#39;darwin_x86_64&#39;</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>The direct solution is to disable the universal build by changing `_universal` to `_native` in that configuration.</span></span>\n<span class="line"><span>The least intrusive way to do this is to edit `ReactantExtra/WORKSPACE` to add a new patch to the XLA dependency.</span></span>\n<span class="line"><span>Replace the line which reads</span></span></code></pre></div><p>NEW_XLA_PATCHES = []</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>\n<span class="line"><span>with</span></span></code></pre></div><p>NEW_XLA_PATCHES = [ r&quot;&quot;&quot;cat &gt;&gt; third_party/grpc/grpc.patch &lt;&lt; &#39;GRPC_PATCH&#39;</p><h2 id="diff-–git-a-bazel-grpc-build-system-bzl-b-bazel-grpc-build-system-bzl-–-a-bazel-grpc-build-system-bzl-b-bazel-grpc-build-system-bzl-212-7-212-7-native-genrule-name-name-srcs-select" tabindex="-1">diff –git a/bazel/grpc_build_system.bzl b/bazel/grpc_build_system.bzl –- a/bazel/grpc_build_system.bzl +++ b/bazel/grpc_build_system.bzl @@ -212,7 +212,7 @@ native.genrule( name = name, srcs = select({ <a class="header-anchor" href="#diff-–git-a-bazel-grpc-build-system-bzl-b-bazel-grpc-build-system-bzl-–-a-bazel-grpc-build-system-bzl-b-bazel-grpc-build-system-bzl-212-7-212-7-native-genrule-name-name-srcs-select" aria-label="Permalink to &quot;diff –git a/bazel/grpc_build_system.bzl b/bazel/grpc_build_system.bzl –- a/bazel/grpc_build_system.bzl +++ b/bazel/grpc_build_system.bzl @@ -212,7 +212,7 @@      native.genrule(          name = name,          srcs = select({&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       &quot;@platforms//os:macos&quot;: [name + &quot;_universal&quot;],</span></span></code></pre></div><ul><li><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       &quot;@platforms//os:macos&quot;: [name + &quot;_native&quot;],</span></span>\n<span class="line"><span>       &quot;//conditions:default&quot;: [name + &quot;_native&quot;],</span></span>\n<span class="line"><span>   }),</span></span>\n<span class="line"><span>   outs = [name + &quot;_binary&quot;],</span></span></code></pre></div></li></ul><p>GRPC_PATCH&quot;&quot;&quot;, ] ```</p><p>(or if <code>NEW_XLA_PATCHES</code> already contains some patches, just add the <code>cat &gt;&gt; ...</code> command to the list). Don&#39;t be confused by the <code>-</code> and <code>+</code>&#39;s here: copy the text above <em>verbatim</em> into the <code>WORKSPACE</code> file. The text above represents a <em>command that modifies a patch file</em>, it&#39;s not itself a patch.</p><p>What&#39;s going on here? Because grpc isn&#39;t a direct dependency, we can&#39;t easily add a patch to it in Reactant. However, it turns out that XLA itself <a href="https://github.com/openxla/xla/blob/3ede8358116e1795f21e4a8833920ae5ce9f8fdc/third_party/grpc/grpc.patch" target="_blank" rel="noreferrer">contains a file</a> that describes the patches <em>it</em> wants to make to grpc. We are piggybacking on this file to add <em>our</em> own patch to grpc.</p><p>Note that this is pretty fragile and can break if new versions of XLA or grpc are used. However, the description here should hopefully be enough to help you figure out how to fix it if that happens.</p>',36)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
